using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Configure options with a default resolver (reflection-based)
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for: {personInfo.Type.Name}");
Console.WriteLine($"  Kind: {personInfo.Kind}");
Console.WriteLine($"  Properties: {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// Round-trip using the typed metadata
var person = new Person("Alice", 30);
string json = JsonSerializer.Serialize(person, personInfo);
Console.WriteLine($"  Serialized: {json}");

Person deserialized = JsonSerializer.Deserialize(json, personInfo)!;
Console.WriteLine($"  Deserialized: {deserialized}");

Console.WriteLine();

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
//    Use a resolver that only knows about Person, not about UnknownWidget.
var limitedOptions = new JsonSerializerOptions
{
    TypeInfoResolver = new PersonOnlyResolver()
};

bool havePerson = limitedOptions.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? foundPerson);
Console.WriteLine($"TryGetTypeInfo(Person):        found={havePerson}, info={foundPerson?.Type.Name}");

bool haveWidget = limitedOptions.TryGetTypeInfo(typeof(UnknownWidget), out JsonTypeInfo? foundWidget);
Console.WriteLine($"TryGetTypeInfo(UnknownWidget): found={haveWidget}, info={foundWidget?.Type.Name ?? "(null)"}");

// --- Types ---

public record Person(string Name, int Age);
public record UnknownWidget(string Id);

// A custom resolver that only serves metadata for Person
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    private readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return _inner.GetTypeInfo(type, options);
        return null; // signals "I don't know this type"
    }
}
EOF

